# Terraform Azure Provider (azurerm)

The Azure provider (`hashicorp/azurerm`) manages Microsoft Azure resources declaratively with Terraform. It supports resource groups, virtual networks, VMs, storage accounts, AKS clusters, App Services, and hundreds of other Azure resource types.

## Provider Configuration

```hcl
terraform {
  required_providers {
    azurerm = {
      source  = "hashicorp/azurerm"
      version = "~> 3.100"
    }
  }
}

provider "azurerm" {
  features {}

  subscription_id = "00000000-0000-0000-0000-000000000000"
}
```

The `features {}` block is **required** in every azurerm provider configuration, even if it contains no settings. It controls provider-level behavior for certain resource types:

```hcl
provider "azurerm" {
  features {
    resource_group {
      prevent_deletion_if_contains_resources = true
    }
    key_vault {
      purge_soft_delete_on_destroy    = false
      recover_soft_deleted_key_vaults = true
    }
    virtual_machine {
      delete_os_disk_on_deletion     = true
      graceful_shutdown              = false
      skip_shutdown_and_force_delete = false
    }
  }

  subscription_id = var.subscription_id
}
```

## Authentication

The Azure provider supports multiple authentication methods:

### 1. Azure CLI (Local Development)

The simplest approach for local development — authenticate with `az login`:

```bash
az login
az account set --subscription "00000000-0000-0000-0000-000000000000"
```

No additional provider configuration is needed. Terraform reads credentials from the Azure CLI session.

### 2. Service Principal with Client Secret

For CI/CD and automated deployments, create a service principal and set environment variables:

```bash
# Create a service principal
az ad sp create-for-rbac --name "terraform-sp" --role Contributor \
  --scopes /subscriptions/00000000-0000-0000-0000-000000000000
```

Set the environment variables:

```bash
export ARM_CLIENT_ID="appId-from-output"
export ARM_CLIENT_SECRET="password-from-output"
export ARM_SUBSCRIPTION_ID="00000000-0000-0000-0000-000000000000"
export ARM_TENANT_ID="tenant-from-output"
```

Or configure in the provider block (not recommended for production):

```hcl
provider "azurerm" {
  features {}

  subscription_id = "00000000-0000-0000-0000-000000000000"
  client_id       = var.arm_client_id
  client_secret   = var.arm_client_secret
  tenant_id       = var.arm_tenant_id
}
```

### 3. Service Principal with Certificate

```bash
export ARM_CLIENT_ID="appId"
export ARM_CLIENT_CERTIFICATE_PATH="/path/to/certificate.pfx"
export ARM_CLIENT_CERTIFICATE_PASSWORD="certificate-password"
export ARM_SUBSCRIPTION_ID="00000000-0000-0000-0000-000000000000"
export ARM_TENANT_ID="tenant-id"
```

### 4. Managed Identity

For Terraform running on Azure VMs, App Service, or Azure Functions with a system-assigned or user-assigned managed identity:

```hcl
provider "azurerm" {
  features {}
  use_msi         = true
  subscription_id = "00000000-0000-0000-0000-000000000000"
}
```

### 5. OIDC Federation (CI/CD)

For GitHub Actions, GitLab CI, and other OIDC-capable CI/CD systems:

```hcl
provider "azurerm" {
  features {}
  use_oidc        = true
  subscription_id = "00000000-0000-0000-0000-000000000000"
}
```

```bash
export ARM_CLIENT_ID="appId"
export ARM_SUBSCRIPTION_ID="00000000-0000-0000-0000-000000000000"
export ARM_TENANT_ID="tenant-id"
export ARM_OIDC_TOKEN="token-from-ci-provider"
```

## Common Resources

```hcl
# Resource group — every Azure resource belongs to one
resource "azurerm_resource_group" "main" {
  name     = "rg-myapp-${var.environment}"
  location = "East US"

  tags = {
    ManagedBy   = "terraform"
    Environment = var.environment
  }
}

# Virtual network
resource "azurerm_virtual_network" "main" {
  name                = "vnet-main"
  address_space       = ["10.0.0.0/16"]
  location            = azurerm_resource_group.main.location
  resource_group_name = azurerm_resource_group.main.name
}

# Subnet
resource "azurerm_subnet" "internal" {
  name                 = "snet-internal"
  resource_group_name  = azurerm_resource_group.main.name
  virtual_network_name = azurerm_virtual_network.main.name
  address_prefixes     = ["10.0.1.0/24"]
}

# Network security group
resource "azurerm_network_security_group" "web" {
  name                = "nsg-web"
  location            = azurerm_resource_group.main.location
  resource_group_name = azurerm_resource_group.main.name

  security_rule {
    name                       = "AllowHTTP"
    priority                   = 100
    direction                  = "Inbound"
    access                     = "Allow"
    protocol                   = "Tcp"
    source_port_range          = "*"
    destination_port_range     = "80"
    source_address_prefix      = "*"
    destination_address_prefix = "*"
  }

  security_rule {
    name                       = "AllowHTTPS"
    priority                   = 110
    direction                  = "Inbound"
    access                     = "Allow"
    protocol                   = "Tcp"
    source_port_range          = "*"
    destination_port_range     = "443"
    source_address_prefix      = "*"
    destination_address_prefix = "*"
  }
}

# Network interface
resource "azurerm_network_interface" "web" {
  name                = "nic-web"
  location            = azurerm_resource_group.main.location
  resource_group_name = azurerm_resource_group.main.name

  ip_configuration {
    name                          = "internal"
    subnet_id                     = azurerm_subnet.internal.id
    private_ip_address_allocation = "Dynamic"
  }
}

# Linux virtual machine
resource "azurerm_linux_virtual_machine" "web" {
  name                = "vm-web"
  resource_group_name = azurerm_resource_group.main.name
  location            = azurerm_resource_group.main.location
  size                = "Standard_B1s"
  admin_username      = "adminuser"

  network_interface_ids = [azurerm_network_interface.web.id]

  admin_ssh_key {
    username   = "adminuser"
    public_key = file("~/.ssh/id_rsa.pub")
  }

  os_disk {
    caching              = "ReadWrite"
    storage_account_type = "Standard_LRS"
  }

  source_image_reference {
    publisher = "Canonical"
    offer     = "0001-com-ubuntu-server-jammy"
    sku       = "22_04-lts"
    version   = "latest"
  }
}

# Storage account
resource "azurerm_storage_account" "data" {
  name                     = "stmyappdata${var.environment}"
  resource_group_name      = azurerm_resource_group.main.name
  location                 = azurerm_resource_group.main.location
  account_tier             = "Standard"
  account_replication_type = "LRS"

  blob_properties {
    versioning_enabled = true
  }
}

# AKS cluster
resource "azurerm_kubernetes_cluster" "main" {
  name                = "aks-main"
  location            = azurerm_resource_group.main.location
  resource_group_name = azurerm_resource_group.main.name
  dns_prefix          = "aks-main"

  default_node_pool {
    name       = "default"
    node_count = 3
    vm_size    = "Standard_D2s_v3"
  }

  identity {
    type = "SystemAssigned"
  }

  network_profile {
    network_plugin = "azure"
    network_policy = "calico"
  }
}
```

## Data Sources

Data sources query existing Azure resources:

```hcl
# Current client config (subscription, tenant, object ID)
data "azurerm_client_config" "current" {}

output "tenant_id" {
  value = data.azurerm_client_config.current.tenant_id
}

output "subscription_id" {
  value = data.azurerm_client_config.current.subscription_id
}

# Current subscription details
data "azurerm_subscription" "current" {}

output "subscription_name" {
  value = data.azurerm_subscription.current.display_name
}

# Existing resource group
data "azurerm_resource_group" "existing" {
  name = "rg-shared-services"
}

output "rg_location" {
  value = data.azurerm_resource_group.existing.location
}
```

## Environment Variables Reference

| Variable | Purpose |
|----------|----------|
| `ARM_CLIENT_ID` | Service principal application (client) ID |
| `ARM_CLIENT_SECRET` | Service principal client secret |
| `ARM_CLIENT_CERTIFICATE_PATH` | Path to client certificate file (.pfx) |
| `ARM_CLIENT_CERTIFICATE_PASSWORD` | Password for the client certificate |
| `ARM_SUBSCRIPTION_ID` | Azure subscription ID |
| `ARM_TENANT_ID` | Azure Active Directory tenant ID |
| `ARM_OIDC_TOKEN` | OIDC token for federated identity |
| `ARM_USE_MSI` | Set to `true` for managed identity authentication |
| `ARM_USE_OIDC` | Set to `true` for OIDC authentication |
